	private void UpdateCurrentReward(PubgCalendarDayInfo? reward, bool hasActiveDay)
	{
		if (reward == null || !hasActiveDay)
		{
			CurrentRewardDayLabel.Text = Loc.GetString("pubg-prelobby-calendar-next-day-complete");
			CurrentRewardLabel.Text = Loc.GetString("pubg-prelobby-calendar-current-reward-empty");
			CurrentRewardIcon.Texture = _fallbackTexture;
		}
		else
		{
			CurrentRewardDayLabel.Text = Loc.GetString("pubg-prelobby-calendar-current-reward-day", new(string, object)[1] { ("day", reward.Day) });
			CurrentRewardLabel.Text = GetRewardText(reward);
			CurrentRewardIcon.Texture = GetRewardIcon(reward.RewardType);
		}
	}

